with detail = 0 {
    with link = "line.dk.FPB" {
        let fa = path("d0.dk.ffh.1");
        let af = path("d0.dk.ffh.2");

        with railway = :first :double :pax {
            track(fa[:fre, :vej.yh]);
            track(fa[:vej.yh, :aar.yr]);
            track(fa[:aar.yr, :aar]);
            track(af[:aar.yr, :aal.yh]);
            track(af[:aal.yh, :lin.yl]);
        }

        with railway = :first :pax {
            track(af[:lin.yl, :hjo.yh]);
            track(af[:hjo.yh, :fre]);
        }
    }

    with link = "line.dk.FPB" {
        let fp = path("d0.dk.fpb");

        with railway = :first :double :cat:ac25 :pax {
            track(fp[:fre, :lun.ye]);
            track(fp[:lun.ye, :tin]);
        }
        track(:first :cat:ac25 :pax, fp[:tin, :pag]);
    }

    with link = "line.dk.HBV" {
        track(:first :pax, path("d0.dk.hbv")[:her, :vej.yh]);
    }

    with link = "line.dk.LES" {
        track(:first :double :cat:ac25 :pax,
                path("d0.dk.les.1")[:lun.ye, :esb]
        );
    }

    with link = "line.dk.KFA" {
        let kf = path("d0.dk.kfa");

        with railway = :first :double :cat:ac25 :pax {
            track(kf[:kob, :kva.yk]);
            track(kf[:kva.yk, :rin.yr]);
            track(kf[:rin.yr, :fre]);
        }
    }

    with link = "line.dk.KPH" {
        track(:first :double :cat:ac25 :pax, path("d0.dk.kph")[:kob, :peg]);
    }

    with link = "line.dk.RSR" {
        let rr = path("d0.dk.rsr");

        track(:first :double :cat:ac25 :pax, rr[:rin.yr, :vor]);
        track(:first :pax, rr[:vor, :ore]);
        track(:first :double :pax, rr[:ore, :nyk]);
        track(:first :suspended, rr[:nyk, :rof]);
    }

    with link = "line.dk.VRS" {
        track(:first :double :cat:ac25 :pax,
                path("d0.dk.vrs")[:vig.yr, :kva.yk]
        );
    }
}

